// Deterministic build animation based on structure type and position
const structureType = action.type;
const x = action.x;
const y = action.y;
const seed = kernel.getState().seed;
const tick = kernel.getState().tick;

// Deterministic animation parameters
const animationDuration = 1000 + (seed.charCodeAt(structureType.charCodeAt(0) % 10) * 100);
const particleCount = 5 + (x + y) % 10;
const color = this.getDeterministicColor(structureType, seed);

// Create deterministic build effect
const buildEffect = {
  type: 'visual_effect',
  data: {
    animation: 'build',
    duration: animationDuration,
    particles: particleCount,
    color: color,
    position: { x, y },
    structureType: structureType,
    tick: tick,
    seed: seed
  }
};

kernel.logEvent({
  type: 'deterministic_build_effect',
  structureType,
  position: { x, y },
  effect: buildEffect
});

return state; // Don't modify game state, only visual effects

