// Deterministic UI Plugin - Kernel Controlled
// SEED=SAME ACTIONS = GLEICHER SEED

// Deterministic color generator
function getDeterministicColor(input, seed) {
  const hash = ((seed.charCodeAt(0) * 31) + input.charCodeAt(0)) % 360;
  return `hsl(${hash}, 70%, 50%)`;
}

// Deterministic animation timing
function getDeterministicTiming(tick, seed) {
  const base = 1000;
  const variation = (seed.charCodeAt(0) % 500);
  return base + variation + (tick % 100);
}

// Handle tick events deterministically
sandbox.onTick = function(eventData) {
  const tick = sandbox.time.tick();
  const seed = sandbox.kernel.getState().seed;

  // Update UI with deterministic values
  const uiState = {
    tick: tick,
    seed: seed,
    color: getDeterministicColor('tick', seed),
    timing: getDeterministicTiming(tick, seed)
  };

  // Safe UI update through kernel
  sandbox.ui.updateElement(document.body, {
    style: {
      backgroundColor: uiState.color,
      transition: `all ${uiState.timing}ms ease-in-out`
    }
  });

  sandbox.kernel.logEvent({
    type: 'deterministic_tick_ui_update',
    uiState: uiState
  });
};

// Handle tile selection deterministically
sandbox.onTileSelect = function(tile, currentState) {
  const seed = sandbox.kernel.getState().seed;
  const tileHash = ((tile.x * 31) + (tile.y * 17)) % 360;

  // Deterministic highlight color
  const highlightColor = `hsl(${tileHash}, 80%, 60%)`;

  // Safe UI update
  const tileElement = document.querySelector(`[data-x="${tile.x}"][data-y="${tile.y}"]`);
  if (tileElement && tileElement.hasAttribute('data-kernel-controlled')) {
    sandbox.ui.updateElement(tileElement, {
      style: {
        borderColor: highlightColor,
        boxShadow: `0 0 10px ${highlightColor}`
      }
    });
  }

  sandbox.kernel.logEvent({
    type: 'deterministic_tile_selection',
    tile: tile,
    highlightColor: highlightColor
  });
};

// Handle events deterministically
sandbox.onEvent = function(eventType, eventData) {
  const seed = sandbox.kernel.getState().seed;
  const tick = sandbox.time.tick();

  // Deterministic event response
  if (eventType === 'structurePlaced') {
    const celebrationColor = getDeterministicColor(eventData.type, seed);
    const celebrationDuration = getDeterministicTiming(tick, seed);

    // Create deterministic celebration
    sandbox.ui.createElement('div', {
      className: 'deterministic-celebration',
      style: {
        position: 'absolute',
        color: celebrationColor,
        animationDuration: `${celebrationDuration}ms`,
        pointerEvents: 'none'
      },
      textContent: '✨'
    });

    sandbox.kernel.logEvent({
      type: 'deterministic_celebration',
      eventData: eventData,
      celebration: {
        color: celebrationColor,
        duration: celebrationDuration
      }
    });
  }
};
